.empty-state[data-v-30fb0e92] {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 60px 20px;
  color: #666;
}
.empty-icon[data-v-30fb0e92] {
  font-size: 64px;
  margin-bottom: 15px;
}

