.btn[data-v-30fb0e92] {
  padding: 10px 20px;
  border: 1px solid #ddd;
  border-radius: 4px;
  cursor: pointer;
  font-size: 14px;
  transition: all 0.2s;
}
.btn[data-v-30fb0e92]:hover:not(:disabled) {
  background: #f0f0f0;
}
.btn[data-v-30fb0e92]:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
.btn-primary[data-v-30fb0e92] {
  background: #0082c9;
  color: white;
  border-color: #0082c9;
}
.btn-primary[data-v-30fb0e92]:hover:not(:disabled) {
  background: #006ba6;
}
.btn-secondary[data-v-30fb0e92] {
  background: white;
  color: #333;
}
.btn-danger[data-v-30fb0e92] {
  background: #e74c3c;
  color: white;
  border-color: #e74c3c;
}
.btn-danger[data-v-30fb0e92]:hover:not(:disabled) {
  background: #c0392b;
}
.spinner[data-v-30fb0e92] {
  display: inline-block;
  width: 14px;
  height: 14px;
  border: 2px solid rgba(255, 255, 255, 0.3);
  border-top-color: currentColor;
  border-radius: 50%;
  animation: spin-30fb0e92 0.6s linear infinite;
  margin-right: 8px;
  vertical-align: middle;
}

/* Breadcrumb Navigation */
.breadcrumb-nav[data-v-30fb0e92] {
