  gap: 4px;
  padding: 12px 20px;
  background: var(--color-background-hover);
  border-radius: var(--border-radius);
  margin-bottom: 16px;
  overflow-x: auto;
}
.breadcrumb-item[data-v-30fb0e92] {
  background: none;
  border: none;
  color: var(--color-primary);
  cursor: pointer;
  padding: 4px 8px;
  border-radius: var(--border-radius);
  font-size: 14px;
  white-space: nowrap;
  transition: background 0.2s;
}
.breadcrumb-item[data-v-30fb0e92]:hover {
  background: var(--color-primary-element-light);
}
.breadcrumb-separator[data-v-30fb0e92] {
  color: var(--color-text-maxcontrast);
  margin: 0 4px;
}

/* Folder Styling */
.media-item.is-folder[data-v-30fb0e92] {
  cursor: pointer;
}
.media-item.is-folder[data-v-30fb0e92]:hover {
  background: var(--color-primary-element-light);
}
.folder-icon[data-v-30fb0e92] {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100px;
  font-size: 48px;
}
.media-type[data-v-30fb0e92] {
  font-size: 12px;
  color: var(--color-text-maxcontrast);
}
