-- Tab Content -->\r\n    <div class=\"media-picker-content\">\r\n      <!-- Upload Tab -->\r\n      <div v-if=\"activeTab === 'upload'\" class=\"tab-panel\" role=\"tabpanel\">\r\n        <div class=\"upload-section\">\r\n          <input\r\n            ref=\"fileInput\"\r\n            type=\"file\"\r\n            :accept=\"acceptTypes\"\r\n            class=\"file-input\"\r\n            :aria-label=\"mediaType === 'image' ? t('Select image file') : t('Select video file')\"\r\n            @change=\"handleFileSelect\"\r\n          />\r\n\r\n          <div v-if=\"!selectedFile\" class=\"upload-prompt\" @click=\"$refs.fileInput.click()\">\r\n            <div class=\"upload-icon\">📁</div>\r\n            <p>{{ mediaType === 'image' ? t('Click to select an image') : t('Click to select a video') }}</p>\r\n            <p class=\"hint\">{{ t('or drag and drop') }}</p>\r\n          </div>\r\n\r\n          <div v-else class=\"file-selected\">\r\n            <div class=\"file-info\">\r\n              <span class=\"file-icon\">{{ mediaType === 'image' ? '🖼️' : '🎬' }}</span>\r\n              <div class=\"file-details\">\r\n                <div class=\"file-name\">{{ selectedFile.name }}</div>\r\n                <div class=\"file-size\">{{ formatFileSize(selectedFile.size) }}</div>\r\n              </div>\r\n            </div>\r\n            <button type=\"button\" @click=\"clearFile\" class=\"btn-remove\" :aria-label=\"t('Remove file')\">✕</button>\r\n          </div>\r\n\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Page Media Tab -->\r\n      <div v-if=\"activeTab === 'page'\" class=\"tab-panel\" role=\"tabpanel\">\r\n        <div v-if=\"isLoadingMedia\" class=\"loading-state\">\r\n          <span class=\"loading-spinner\"></span>\r\n          <p>{{ t('Loading media...') }}</p>\r\n        </div>\r\n\r\n        <div v-else-if=\"filteredPageMedia.length === 0\" class=\"empty-state\">\r\n          <div class=\"empty-icon\">📭</div>\r\n          <p>{{ t('No media files in this page yet') }}</p>\r\n          <p class=\"hint\">{{ t('Upload files to see them here') }}</p>\r\n        </div>\r\n\r\n        <div v-else class=\"media-grid\">\r\n          <div\r\n            v-for=\"media in filteredPageMedia\"\r\n            :key=\"media.name\"\r\n            :class=\"['media-item', { selected: selectedMedia?.name === media.name && selectedMedia?.folder === 'page' }]\"\r\n            @click=\"selectMedia(media, 'page')\"\r\n          >\r\n            <div class=\"media-thumbnail\">\r\n              <img\r\n                v-if=\"isImage(media.mimeType)\"\r\n                :src=\"getMediaThumbnail(media, 'page')\"\r\n                :alt=\"media.name\"\r\n              />\r\n              <div v-else class=\"video-placeholder\">\r\n                <span>🎬</span>\r\n              </div>\r\n            </div>\r\n            <div class=\"media-info\">\r\n              <div class=\"media-name\" :title=\"media.name\">{{ media.name }}</div>\r\n              <div class=\"media-size\">{{ formatFileSize(media.size) }}</div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Resources Tab -->\r\n      <div v-if=\"activeTab === 'resources'\" class=\"tab-panel\" role=\"tabpanel\">\r\n        <!-- Breadcrumb Navigation -->\r\n        <div v-if=\"currentResourcesPath\" class=\"breadcrumb-nav\">\r\n          <button\r\n            class=\"breadcrumb-item\"\r\n            @click=\"navigateToFolder('')\"\r\n          >\r\n            📚 {{ t('Shared Library') }}\r\n          </button>\r\n          <span v-for=\"(segment, index) in breadcrumbSegments\" :key=\"index\">\r\n            <span class=\"breadcrumb-separator\">/</span>\r\n            <button\r\n              class=\"breadcrumb-item\"\r\n              @click=\"navigateToFolder(getPathUpTo(index))\"\r\n            >\r\n              {{ segment }}\r\n            </button>\r\n          </span>\r\n        </div>\r\n\r\n        <div v-if=\"isLoadingMedia\" class=\"loading-state\">\r\n          <span class=\"loading-spinner\"></span>\r\n          <p>{{ t('Loading shared media...') }}</p>\r\n        </div>\r\n\r\n        <div v-else-if=\"filteredResourcesMedia.length === 0\" class=\"empty-state\">\r\n          <div class=\"empty-icon\">📚</div>\r\n          <p>{{ t('No media in shared library yet') }}</p>\r\n          <p class=\"hint\">{{ t('Upload to shared library to see files here') }}</p>\r\n        </div>\r\n\r\n        <div v-else class=\"media-grid\">\r\n          <div\r\n            v-for=\"item in filteredResourcesMedia\"\r\n            :key=\"item.name\"\r\n            :class=\"['media-item', {\r\n              selected: item.type === 'file' && selectedMedia?.path === item.path && selectedMedia?.folder === 'resources',\r\n              'is-folder': item.type === 'folder'\r\n            }]\"\r\n            @click=\"item.type === 'folder' ? handleFolderClick(item) : selectMedia(item, 'resources')\"\r\n          >\r\n            <div class=\"media-thumbnail\">\r\n              <div v-if=\"item.type === 'folder'\" class=\"folder-icon\">\r\n                📁\r\n              </div>\r\n              <img\r\n                v-else-if=\"isImage(item.mimeType)\"\r\n                :src=\"getMediaThumbnail(item, 'resources')\"\r\n                :alt=\"item.name\"\r\n              />\r\n              <div v-else class=\"video-placeholder\">\r\n                <span>🎬</span>\r\n              </div>\r\n            </div>\r\n            <div class=\"media-info\">\r\n              <div class=\"media-name\" :title=\"item.name\">{{ item.name }}</div>\r\n              <div v-if=\"item.type === 'file'\" class=\"media-size\">{{ formatFileSize(item.size) }}</div>\r\n              <div v-else class=\"media-type\">{{ t('Folder') }}</div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Dialog Actions -->\r\n    <template #actions>\r\n      <NcButton @click=\"handleClose\">\r\n        {{ t('Cancel') }}\r\n      </NcButton>\r\n      <NcButton\r\n        type=\"primary\"\r\n        :disabled=\"isUploading || (!selectedFile && !selectedMedia)\"\r\n        @click=\"handleConfirm\"\r\n      >\r\n        <template #icon>\r\n          <span v-if=\"isUploading\" class=\"icon-loading-small\"></span>\r\n        </template>\r\n        {{ confirmButtonLabel }}\r\n      </NcButton>\r\n    </template>\r\n\r\n    <!-- Duplicate Warning Dialog -->\r\n    <NcDialog\r\n      v-if=\"showDuplicateDialog\"\r\n      :open=\"showDuplicateDialog\"\r\n      :name=\"t('File Already Exists')\"\r\n      size=\"small\"\r\n      @update:open=\"showDuplicateDialog = false\"\r\n    >\r\n      <p>{{ t('A file with the name \"{filename}\" already exists.', { filename: duplicateFilename }) }}</p>\r\n      <p>{{ t('What would you like to do?') }}</p>\r\n\r\n      <template #actions>\r\n        <NcButton @click=\"handleDuplicateCancel\">\r\n          {{ t('Cancel') }}\r\n        </NcButton>\r\n        <NcButton @click=\"handleDuplicateRename\">\r\n          {{ t('Use different name') }}\r\n        </NcButton>\r\n        <NcButton\r\n          type=\"error\"\r\n          @click=\"handleDuplicateOverwrite\"\r\n        >\r\n          {{ t('Overwrite') }}\r\n        </NcButton>\r\n      </template>\r\n    </NcDialog>\r\n  </NcDialog>\r\n</template>\r\n\r\n<script>\r\nimport { NcDialog, NcButton } from '@nextcloud/vue'\r\nimport axios from '@nextcloud/axios'\r\nimport { generateUrl } from '@nextcloud/router'\r\nimport { translate as t } from '@nextcloud/l10n'\r\nimport { showError } from '@nextcloud/dialogs'\r\n\r\nexport default {\r\n  name: 'MediaPicker',\r\n\r\n  components: {\r\n    NcDialog,\r\n    NcButton\r\n  },\r\n\r\n  props: {\r\n    open: {\r\n      type: Boolean,\r\n      required: true\r\n    },\r\n    pageId: {\r\n      type: String,\r\n      required: true\r\n    },\r\n    mediaType: {\r\n      type: String,\r\n      required: true,\r\n      validator: (value) => ['image', 'video'].includes(value)\r\n    },\r\n    title: {\r\n      type: String,\r\n      default: () => t('intravox', 'Select Media')\r\n    }\r\n  },\r\n\r\n  emits: ['close', 'select'],\r\n\r\n  data() {\r\n    return {\r\n      activeTab: 'upload',\r\n      selectedFile: null,\r\n      uploadTarget: 'page',\r\n      selectedMedia: null,\r\n      pageMediaList: [],\r\n      resourcesMediaList: [],\r\n      isLoadingMedia: false,\r\n      isUploading: false,\r\n      showDuplicateDialog: false,\r\n      duplicateFilename: '',\r\n      pendingUpload: null,\r\n      currentResourcesPath: '', // NEW: Current subfolder path\r\n      folderHistory: []         // NEW: For back navigation\r\n    }\r\n  },\r\n\r\n  computed: {\r\n    acceptTypes() {\r\n      if (this.mediaType === 'image') {\r\n        return 'image/jpeg,image/png,image/gif,image/webp,image/svg+xml'\r\n      }\r\n      return 'video/mp4,video/webm,video/ogg'\r\n    },\r\n\r\n    confirmButtonLabel() {\r\n      if (this.isUploading) {\r\n        return this.t('Uploading...')\r\n      }\r\n      if (this.activeTab === 'upload' && this.selectedFile) {\r\n        return this.t('Upload')\r\n      }\r\n      return this.t('Select')\r\n    },\r\n\r\n    filteredPageMedia() {\r\n      return this.filterMediaByType(this.pageMediaList)\r\n    },\r\n\r\n    filteredResourcesMedia() {\r\n      return this.filterMediaByType(this.resourcesMediaList)\r\n    },\r\n\r\n    breadcrumbSegments() {\r\n      if (!this.currentResourcesPath) return []\r\n      return this.currentResourcesPath.split('/').filter(s => s)\r\n    }\r\n  },\r\n\r\n  watch: {\r\n    open(newVal) {\r\n      if (newVal) {\r\n        this.resetState()\r\n      }\r\n    }\r\n  },\r\n\r\n  methods: {\r\n    t(key, vars = {}) {\r\n      return t('intravox', key, vars)\r\n    },\r\n\r\n    handleClose() {\r\n      this.$emit('close')\r\n    },\r\n\r\n    resetState() {\r\n      this.activeTab = 'upload'\r\n      this.selectedFile = null\r\n      this.uploadTarget = 'page'\r\n      this.selectedMedia = null\r\n      this.pageMediaList = []\r\n      this.resourcesMediaList = []\r\n      this.isLoadingMedia = false\r\n    },\r\n\r\n    handleFileSelect(event) {\r\n      const file = event.target.files[0]\r\n      if (file) {\r\n        this.selectedFile = file\r\n        this.selectedMedia = null\r\n      }\r\n    },\r\n\r\n    clearFile() {\r\n      this.selectedFile = null\r\n      if (this.$refs.fileInput) {\r\n        this.$refs.fileInput.value = ''\r\n      }\r\n    },\r\n\r\n    filterMediaByType(mediaList) {\r\n      if (!mediaList || mediaList.length === 0) {\r\n        return []\r\n      }\r\n\r\n      const imageTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/svg+xml']\r\n      const videoTypes = ['video/mp4', 'video/webm', 'video/ogg']\r\n\r\n      return mediaList.filter(media => {\r\n        // Always include folders (they don't have mimeType)\r\n        if (media.type === 'folder') {\r\n          return true\r\n        }\r\n\r\n        if (this.mediaType === 'image') {\r\n          return imageTypes.includes(media.mimeType)\r\n        } else if (this.mediaType === 'video') {\r\n          return videoTypes.includes(media.mimeType)\r\n        }\r\n        return true\r\n      })\r\n    },\r\n\r\n    async switchToTab(tab) {\r\n      this.activeTab = tab\r\n      if (tab === 'page' && this.pageMediaList.length === 0) {\r\n        await this.loadPageMedia()\r\n      } else if (tab === 'resources' && this.resourcesMediaList.length === 0) {\r\n        await this.loadResourcesMedia()\r\n      }\r\n    },\r\n\r\n    async loadPageMedia() {\r\n      this.isLoadingMedia = true\r\n      try {\r\n        const response = await axios.get(\r\n          generateUrl(`/apps/intravox/api/pages/${this.pageId}/media/list`),\r\n          { params: { folder: 'page' } }\r\n        )\r\n        this.pageMediaList = response.data.media || []\r\n      } catch (error) {\r\n        console.error('Failed to load page media:', error)\r\n      } finally {\r\n        this.isLoadingMedia = false\r\n      }\r\n    },\r\n\r\n    async loadResourcesMedia(path = '') {\r\n      this.isLoadingMedia = true\r\n      try {\r\n        const response = await axios.get(\r\n          generateUrl(`/apps/intravox/api/pages/${this.pageId}/media/list`),\r\n          {\r\n            params: {\r\n              folder: 'resources',\r\n              path: path\r\n            }\r\n          }\r\n        )\r\n        this.currentResourcesPath = path\r\n        this.resourcesMediaList = response.data.media || []\r\n      } catch (error) {\r\n        console.error('Failed to load resources media:', error)\r\n      } finally {\r\n        this.isLoadingMedia = false\r\n      }\r\n    },\r\n\r\n    selectMedia(media, folder) {\r\n      // Store full path for resources media\r\n      this.selectedMedia = {\r\n        ...media,\r\n        folder,\r\n        path: media.path || media.name // Ensure path is always set\r\n      }\r\n      this.selectedFile = null\r\n    },\r\n\r\n    navigateToFolder(path) {\r\n      this.loadResourcesMedia(path)\r\n    },\r\n\r\n    getPathUpTo(index) {\r\n      return this.breadcrumbSegments.slice(0, index + 1).join('/')\r\n    },\r\n\r\n    handleFolderClick(item) {\r\n      if (item.type === 'folder') {\r\n        this.loadResourcesMedia(item.path)\r\n      }\r\n    },\r\n\r\n    async handleConfirm() {\r\n      if (this.selectedFile) {\r\n        await this.performUpload()\r\n      } else if (this.selectedMedia) {\r\n        this.$emit('select', {\r\n          filename: this.selectedMedia.path || this.selectedMedia.name, // Use path for subfolders\r\n          folder: this.selectedMedia.folder\r\n        })\r\n      }\r\n    },\r\n\r\n    async performUpload(overwrite = false) {\r\n      if (!this.selectedFile) return\r\n\r\n      this.isUploading = true\r\n\r\n      try {\r\n        // Check for duplicates if not overwriting\r\n        if (!overwrite) {\r\n          const checkFormData = new FormData()\r\n          checkFormData.append('filename', this.selectedFile.name)\r\n          checkFormData.append('target', this.uploadTarget)\r\n\r\n          const checkResponse = await axios.post(\r\n            generateUrl(`/apps/intravox/api/pages/${this.pageId}/media/check`),\r\n            checkFormData\r\n          )\r\n\r\n          if (checkResponse.data.exists) {\r\n            this.duplicateFilename = this.selectedFile.name\r\n            this.showDuplicateDialog = true\r\n            this.isUploading = false\r\n            return\r\n          }\r\n        }\r\n\r\n        // Upload file\r\n        const formData = new FormData()\r\n        formData.append('media', this.selectedFile)\r\n        formData.append('target', this.uploadTarget)\r\n        if (overwrite) {\r\n          formData.append('overwrite', '1')\r\n        }\r\n\r\n        const response = await axios.post(\r\n          generateUrl(`/apps/intravox/api/pages/${this.pageId}/media/upload`),\r\n          formData,\r\n          {\r\n            headers: {\r\n              'Content-Type': 'multipart/form-data'\r\n            }\r\n          }\r\n        )\r\n\r\n        // Upload successful, emit select event\r\n        this.$emit('select', {\r\n          filename: response.data.filename,\r\n          folder: this.uploadTarget\r\n        })\r\n\r\n      } catch (error) {\r\n        console.error('Upload failed:', error)\r\n        showError(this.t('Upload failed: ') + (error.response?.data?.error || error.message))\r\n      } finally {\r\n        this.isUploading = false\r\n      }\r\n    },\r\n\r\n    handleDuplicateCancel() {\r\n      this.showDuplicateDialog = false\r\n      this.duplicateFilename = ''\r\n    },\r\n\r\n    handleDuplicateRename() {\r\n      this.showDuplicateDialog = false\r\n      this.duplicateFilename = ''\r\n      alert(this.t('Please rename the file and try again'))\r\n    },\r\n\r\n    async handleDuplicateOverwrite() {\r\n      this.showDuplicateDialog = false\r\n      await this.performUpload(true)\r\n    },\r\n\r\n    formatFileSize(bytes) {\r\n      if (bytes === 0) return '0 B'\r\n      const k = 1024\r\n      const sizes = ['B', 'KB', 'MB', 'GB']\r\n      const i = Math.floor(Math.log(bytes) / Math.log(k))\r\n      return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i]\r\n    },\r\n\r\n    isImage(mimeType) {\r\n      return mimeType?.startsWith('image/')\r\n    },\r\n\r\n    getMediaThumbnail(media, folder) {\r\n      if (folder === 'resources') {\r\n        // Use path for resources (supports subfolders)\r\n        const path = media.path || media.name\r\n\r\n        // Split path into folder and filename for two-parameter route\r\n        const lastSlashIndex = path.lastIndexOf('/')\r\n        if (lastSlashIndex > 0) {\r\n          // Path contains subfolder (e.g., \"icons/document-icon.svg\")\r\n          const folderPart = path.substring(0, lastSlashIndex)\r\n          const filenamePart = path.substring(lastSlashIndex + 1)\r\n          return generateUrl(`/apps/intravox/api/resources/media/${folderPart}/${filenamePart}`)\r\n        } else {\r\n          // Path is just filename (root level)\r\n          return generateUrl(`/apps/intravox/api/resources/media/${path}`)\r\n        }\r\n      }\r\n      return generateUrl('/apps/intravox/api/pages/{pageId}/media/{filename}', {\r\n        pageId: this.pageId,\r\n        filename: media.name\r\n      })\r\n    }\r\n  }\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.media-picker-tabs {\r\n  display: flex;\r\n  gap: 8px;\r\n  border-bottom: 2px solid #e0e0e0;\r\n  margin-bottom: 20px;\r\n}\r\n\r\n.tab-button {\r\n  padding: 10px 20px;\r\n  border: none;\r\n  background: transparent;\r\n  cursor: pointer;\r\n  font-size: 14px;\r\n  font-weight: 500;\r\n  color: #666;\r\n  border-bottom: 2px solid transparent;\r\n  margin-bottom: -2px;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.tab-button:hover {\r\n  color: #0082c9;\r\n}\r\n\r\n.tab-button.active {\r\n  color: #0082c9;\r\n  border-bottom-color: #0082c9;\r\n}\r\n\r\n.media-picker-content {\r\n  min-height: 400px;\r\n  max-height: 500px;\r\n  overflow-y: auto;\r\n}\r\n\r\n.tab-panel {\r\n  padding: 10px 0;\r\n}\r\n\r\n/* Upload Tab Styles */\r\n.upload-section {\r\n  display: flex;\r\n  flex-direction: column;\r\n  gap: 20px;\r\n}\r\n\r\n.file-input {\r\n  display: none;\r\n}\r\n\r\n.upload-prompt {\r\n  border: 2px dashed #ccc;\r\n  border-radius: 8px;\r\n  padding: 60px 20px;\r\n  text-align: center;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.upload-prompt:hover {\r\n  border-color: #0082c9;\r\n  background: #f0f9ff;\r\n}\r\n\r\n.upload-icon {\r\n  font-size: 64px;\r\n  margin-bottom: 15px;\r\n}\r\n\r\n.upload-prompt p {\r\n  margin: 5px 0;\r\n  color: #666;\r\n}\r\n\r\n.hint {\r\n  font-size: 12px;\r\n  color: #999;\r\n}\r\n\r\n.file-selected {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  padding: 15px;\r\n  background: #f8f9fa;\r\n  border: 1px solid #ddd;\r\n  border-radius: 8px;\r\n}\r\n\r\n.file-info {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  flex: 1;\r\n}\r\n\r\n.file-icon {\r\n  font-size: 32px;\r\n}\r\n\r\n.file-details {\r\n  flex: 1;\r\n}\r\n\r\n.file-name {\r\n  font-weight: 600;\r\n  margin-bottom: 4px;\r\n  word-break: break-word;\r\n}\r\n\r\n.file-size {\r\n  font-size: 12px;\r\n  color: #666;\r\n}\r\n\r\n.btn-remove {\r\n  background: none;\r\n  border: none;\r\n  cursor: pointer;\r\n  font-size: 24px;\r\n  color: #999;\r\n  padding: 5px 10px;\r\n  transition: color 0.2s;\r\n}\r\n\r\n.btn-remove:hover {\r\n  color: #e74c3c;\r\n}\r\n\r\n/* Media Grid Styles */\r\n.media-grid {\r\n  display: grid;\r\n  grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));\r\n  gap: 15px;\r\n}\r\n\r\n.media-item {\r\n  border: 2px solid #ddd;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.media-item:hover {\r\n  border-color: #0082c9;\r\n  box-shadow: 0 2px 8px rgba(0, 130, 201, 0.2);\r\n}\r\n\r\n.media-item.selected {\r\n  border-color: #0082c9;\r\n  background: #f0f9ff;\r\n}\r\n\r\n.media-thumbnail {\r\n  width: 100%;\r\n  height: 120px;\r\n  background: #f5f5f5;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  overflow: hidden;\r\n}\r\n\r\n.media-thumbnail img {\r\n  width: 100%;\r\n  height: 100%;\r\n  object-fit: cover;\r\n}\r\n\r\n.video-placeholder {\r\n  font-size: 48px;\r\n}\r\n\r\n.media-info {\r\n  padding: 10px;\r\n  background: white;\r\n}\r\n\r\n.media-name {\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  margin-bottom: 4px;\r\n  white-space: nowrap;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n\r\n.media-size {\r\n  font-size: 11px;\r\n  color: #666;\r\n}\r\n\r\n/* Loading State */\r\n.loading-state {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  justify-content: center;\r\n  padding: 60px 20px;\r\n  color: #666;\r\n}\r\n\r\n.loading-spinner {\r\n  display: inline-block;\r\n  width: 32px;\r\n  height: 32px;\r\n  border: 3px solid #f3f3f3;\r\n  border-top: 3px solid #0082c9;\r\n  border-radius: 50%;\r\n  animation: spin 1s linear infinite;\r\n  margin-bottom: 15px;\r\n}\r\n\r\n@keyframes spin {\r\n  to { transform: rotate(360deg); }\r\n}\r\n\r\n/* Empty State */\r\n.empty-state {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  justify-content: center;\r\n  padding: 60px 20px;\r\n  color: #666;\r\n}\r\n\r\n.empty-icon {\r\n  font-size: 64px;\r\n  margin-bottom: 15px;\r\n}\r\n\r\n/* Dialog Actions */\r\n.btn {\r\n  padding: 10px 20px;\r\n  border: 1px solid #ddd;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  font-size: 14px;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.btn:hover:not(:disabled) {\r\n  background: #f0f0f0;\r\n}\r\n\r\n.btn:disabled {\r\n  opacity: 0.5;\r\n  cursor: not-allowed;\r\n}\r\n\r\n.btn-primary {\r\n  background: #0082c9;\r