AAyB;AAC3B;AAEA;EACE,aAAa;EACb,mBAAmB;EACnB,QAAQ;EACR,eAAe;EACf,oCAAoC;AACtC;AAEA;EACE,iBAAiB;EACjB,qCAAqC;EACrC,mCAAmC;EACnC,wCAAwC;EACxC,eAAe;EACf,eAAe;AACjB;AAEA;EACE,gCAAgC;EAChC,kCAAkC;EAClC,gCAAgC;AAClC;AAEA;EACE,aAAa;EACb,mBAAmB;EACnB,QAAQ;EACR,iBAAiB;EACjB,sCAAsC;EACtC,mCAAmC;EACnC,uBAAuB;EACvB,oCAAoC;EACpC,eAAe;EACf,eAAe;AACjB;AAEA;EACE,kCAAkC;EAClC,2BAA2B;AAC7B;AAEA;EACE,mBAAmB;EACnB,mBAAmB;EACnB,QAAQ;EACR,aAAa;EACb,yCAAyC;EACzC,mCAAmC;EACnC,oCAAoC;EACpC,eAAe;AACjB;;AAEA,uBAAuB;AACvB;EACE,kBAAkB;AACpB;AAEA;EACE,aAAa;EACb,mBAAmB;EACnB,QAAQ;EACR,eAAe;EACf,kBAAkB;EAClB,+CAA+C;EAC/C,+CAA+C;EAC/C,mCAAmC;EACnC,yCAAyC;EACzC,eAAe;AACjB;AAEA;EACE,cAAc;AAChB","sourcesContent":["<template>\r\n  <div class=\"news-widget-editor\">\r\n    <!-- Widget Title -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"editor-label\" for=\"news-widget-title\">{{ t('Widget title (optional)') }}</label>\r\n      <input\r\n        id=\"news-widget-title\"\r\n        type=\"text\"\r\n        v-model=\"localWidget.title\"\r\n        :placeholder=\"t('e.g., Latest News')\"\r\n        class=\"editor-input\"\r\n        @input=\"emitUpdate\"\r\n      />\r\n    </div>\r\n\r\n    <!-- Background Color -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"editor-label\">{{ t('Background color') }}</label>\r\n      <div class=\"color-presets\">\r\n        <button\r\n          type=\"button\"\r\n          :class=\"{ active: !localWidget.backgroundColor }\"\r\n          @click=\"setBackgroundColor(null)\"\r\n          class=\"color-preset-btn\"\r\n        >\r\n          {{ t('None') }}\r\n        </button>\r\n        <button\r\n          type=\"button\"\r\n          :class=\"{ active: localWidget.backgroundColor === 'var(--color-background-hover)' }\"\r\n          @click=\"setBackgroundColor('var(--color-background-hover)')\"\r\n          class=\"color-preset-btn\"\r\n        >\r\n          {{ t('Light') }}\r\n        </button>\r\n        <button\r\n          type=\"button\"\r\n          :class=\"{ active: localWidget.backgroundColor === 'var(--color-primary-element)' }\"\r\n          @click=\"setBackgroundColor('var(--color-primary-element)')\"\r\n          class=\"color-preset-btn\"\r\n        >\r\n          {{ t('Primary') }}\r\n        </button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Source Location -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"editor-label\">{{ t('Source location') }}</label>\r\n      <PageTreeSelect\r\n        v-model=\"localWidget.sourcePageId\"\r\n        :placeholder=\"t('All pages')\"\r\n        :clearable=\"true\"\r\n        @select=\"handleSourceSelect\"\r\n      />\r\n      <p class=\"editor-hint\">{{ t('Select a page or folder to show content from, including all subpages') }}</p>\r\n    </div>\r\n\r\n    <!-- Layout Selection -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"editor-label\">{{ t('Layout') }}</label>\r\n      <div class=\"layout-options\">\r\n        <button\r\n          v-for=\"layout in layoutOptions\"\r\n          :key=\"layout.value\"\r\n          class=\"layout-option\"\r\n          :class=\"{ 'layout-option--active': localWidget.layout === layout.value }\"\r\n          @click=\"setLayout(layout.value)\"\r\n        >\r\n          <component :is=\"layout.icon\" :size=\"24\" />\r\n          <span>{{ layout.label }}</span>\r\n        </button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Grid Columns (only for grid layout) -->\r\n    <div v-if=\"localWidget.layout === 'grid'\" class=\"editor-section\">\r\n      <label class=\"editor-label\">{{ t('Columns') }}</label>\r\n      <div class=\"columns-selector\">\r\n        <button\r\n          v-for=\"cols in [2, 3, 4]\"\r\n          :key=\"cols\"\r\n          class=\"column-option\"\r\n          :class=\"{ 'column-option--active': localWidget.columns === cols }\"\r\n          @click=\"setColumns(cols)\"\r\n        >\r\n          {{ cols }}\r\n        </button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Autoplay Interval (only for carousel layout) -->\r\n    <div v-if=\"localWidget.layout === 'carousel'\" class=\"editor-section\">\r\n      <label class=\"editor-label\" for=\"news-widget-autoplay\">{{ t('Autoplay interval (seconds)') }}</label>\r\n      <div class=\"limit-selector\">\r\n        <input\r\n          id=\"news-widget-autoplay\"\r\n          type=\"range\"\r\n          v-model.number=\"localWidget.autoplayInterval\"\r\n          min=\"0\"\r\n          max=\"30\"\r\n          class=\"limit-slider\"\r\n          @input=\"emitUpdate\"\r\n        />\r\n        <span class=\"limit-value\">{{ localWidget.autoplayInterval === 0 ? t('Off') : localWidget.autoplayInterval + 's' }}</span>\r\n      </div>\r\n      <p class=\"editor-hint\">{{ t('Set to 0 to disable autoplay') }}</p>\r\n    </div>\r\n\r\n    <!-- Number of items -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"editor-label\" for=\"news-widget-limit\">{{ t('Number of items') }}</label>\r\n      <div class=\"limit-selector\">\r\n        <input\r\n          id=\"news-widget-limit\"\r\n          type=\"range\"\r\n          v-model.number=\"localWidget.limit\"\r\n          min=\"1\"\r\n          max=\"20\"\r\n          class=\"limit-slider\"\r\n          @input=\"emitUpdate\"\r\n        />\r\n        <span class=\"limit-value\">{{ localWidget.limit }}</span>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Sort Options -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"editor-label\" for=\"news-widget-sort-by\">{{ t('Sort by') }}</label>\r\n      <div class=\"sort-options\">\r\n        <select id=\"news-widget-sort-by\" v-model=\"localWidget.sortBy\" class=\"editor-select\" @change=\"emitUpdate\">\r\n          <option value=\"modified\">{{ t('Date modified') }}</option>\r\n          <option value=\"title\">{{ t('Title') }}</option>\r\n        </select>\r\n        <button\r\n          class=\"sort-order-button\"\r\n          @click=\"toggleSortOrder\"\r\n          :title=\"localWidget.sortOrder === 'desc' ? t('Newest first') : t('Oldest first')\"\r\n        >\r\n          <SortDescending v-if=\"localWidget.sortOrder === 'desc'\" :size=\"20\" />\r\n          <SortAscending v-else :size=\"20\" />\r\n        </button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Display Options -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"editor-label\">{{ t('Display options') }}</label>\r\n      <div class=\"display-options\">\r\n        <label class=\"checkbox-option\">\r\n          <input type=\"checkbox\" v-model=\"localWidget.showImage\" @change=\"emitUpdate\" />\r\n          <span>{{ t('Show image') }}</span>\r\n        </label>\r\n        <label class=\"checkbox-option\">\r\n          <input type=\"checkbox\" v-model=\"localWidget.showDate\" @change=\"emitUpdate\" />\r\n          <span>{{ t('Show date') }}</span>\r\n        </label>\r\n        <label class=\"checkbox-option\">\r\n          <input type=\"checkbox\" v-model=\"localWidget.showExcerpt\" @change=\"emitUpdate\" />\r\n          <span>{{ t('Show excerpt') }}</span>\r\n        </label>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Publication Filter -->\r\n    <div class=\"editor-section\">\r\n      <label class=\"checkbox-option publication-filter-option\">\r\n        <input type=\"checkbox\" v-model=\"localWidget.filterPublished\" @change=\"emitUpdate\" />\r\n        <span>{{ t('Show only published pages') }}</span>\r\n      </label>\r\n      <p class=\"editor-hint\">{{ t('Filter pages based on publication and expiration dates configured in admin settings.') }}</p>\r\n\r\n      <div v-if=\"localWidget.filterPublished && !metavoxAvailable\" class=\"publication-warning\">\r\n        <AlertCircle :size=\"16\" />\r\n        <span>{{ t('MetaVox is required for publication filtering but is not available.') }}</span>\r\n      </div>\r\n\r\n      <div v-else-if=\"localWidget.filterPublished && !publicationFieldsConfigured\" class=\"publication-warning\">\r\n        <AlertCircle :size=\"16\" />\r\n        <span>{{ t('Publication date fields have not been configured in admin settings.') }}</span>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- MetaVox Filters -->\r\n    <div class=\"editor-section\" v-if=\"metavoxAvailable\">\r\n      <label class=\"editor-label\">\r\n        {{ t('MetaVox filters') }}\r\n        <span class=\"label-hint\">({{ t('optional') }})</span>\r\n      </label>\r\n\r\n      <div v-if=\"filters.length > 0\" class=\"filters-list\">\r\n        <div v-for=\"(filter, index) in filters\" :key=\"index\" class=\"filter-row\">\r\n          <select v-model=\"filter.fieldName\" class=\"filter-field\" :aria-label=\"t('Filter field')\" @change=\"handleFieldChange(filter)\">\r\n            <option value=\"\">{{ t('Select field') }}</option>\r\n            <option v-for=\"field in metavoxFields\" :key=\"field.field_name\" :value=\"field.field_name\">\r\n              {{ field.field_label || field.field_name }}\r\n            </option>\r\n          </select>\r\n          <select v-model=\"filter.operator\" class=\"filter-operator\" :aria-label=\"t('Filter operator')\" @change=\"handleOperatorChange(filter)\">\r\n            <option v-for=\"op in getOperatorsForField(filter.fieldName)\" :key=\"op.value\" :value=\"op.value\">\r\n              {{ t(op.label) }}\r\n            </option>\r\n          </select>\r\n\r\n          <!-- Value input - conditional based on field type and operator -->\r\n          <template v-if=\"!requiresNoValue(filter.operator)\">\r\n            <!-- Date field -->\r\n            <input\r\n              v-if=\"getFieldType(filter.fieldName) === 'date'\"\r\n              type=\"date\"\r\n              v-model=\"filter.value\"\r\n              class=\"filter-value\"\r\n              :aria-label=\"t('Filter value')\"\r\n              @input=\"emitUpdate\"\r\n            />\r\n\r\n            <!-- Number field -->\r\n            <input\r\n              v-else-if=\"getFieldType(filter.fieldName) === 'number'\"\r\n              type=\"number\"\r\n              v-model=\"filter.value\"\r\n              class=\"filter-value\"\r\n              :placeholder=\"t('Value')\"\r\n              :aria-label=\"t('Filter value')\"\r\n              @input=\"emitUpdate\"\r\n            />\r\n\r\n            <!-- Select field with equals operator -->\r\n            <select\r\n              v-else-if=\"getFieldType(filter.fieldName) === 'select' && filter.operator === 'equals'\"\r\n              v-model=\"filter.value\"\r\n              class=\"filter-value\"\r\n              :aria-label=\"t('Filter value')\"\r\n              @change=\"emitUpdate\"\r\n            >\r\n              <option value=\"\">{{ t('Select value') }}</option>\r\n              <option v-for=\"option in getFieldOptions(filter.fieldName)\" :key=\"option\" :value=\"option\">\r\n                {{ option }}\r\n              </option>\r\n            </select>\r\n\r\n            <!-- Select field with 'in' operator (multiple) -->\r\n            <select\r\n              v-else-if=\"getFieldType(filter.fieldName) === 'select' && filter.operator === 'in'\"\r\n              v-model=\"filter.values\"\r\n              class=\"filter-value filter-value--multi\"\r\n              multiple\r\n              :aria-label=\"t('Filter values')\"\r\n              @change=\"emitUpdate\"\r\n            >\r\n              <option v-for=\"option in getFieldOptions(filter.fieldName)\" :key=\"option\" :value=\"option\">\r\n                {{ option }}\r\n              </option>\r\n            </select>\r\n\r\n            <!-- Multiselect field -->\r\n            <select\r\n              v-else-if=\"getFieldType(filter.fieldName) === 'multiselect'\"\r\n              v-model=\"filter.values\"\r\n              class=\"filter-value filter-value--multi\"\r\n              multiple\r\n              :aria-label=\"t('Filter values')\"\r\n              @change=\"emitUpdate\"\r\n            >\r\n              <option v-for=\"option in getFieldOptions(filter.fieldName)\" :key=\"option\" :value=\"option\">\r\n                {{ option }}\r\n              </option>\r\n            </select>\r\n\r\n            <!-- Text/Textarea field (default) -->\r\n            <input\r\n              v-else\r\n              type=\"text\"\r\n              v-model=\"filter.value\"\r\n              class=\"filter-value\"\r\n              :placeholder=\"t('Value')\"\r\n              :aria-label=\"t('Filter value')\"\r\n              @input=\"emitUpdate\"\r\n            />\r\n          </template>\r\n\r\n          <button class=\"filter-remove\" @click=\"removeFilter(index)\">\r\n            <Close :size=\"16\" />\r\n          </button>\r\n        </div>\r\n\r\n        <div v-if=\"filters.length > 1\" class=\"filter-operator-toggle\">\r\n          <span>{{ t('Match') }}</span>\r\n          <button\r\n            class=\"operator-button\"\r\n            :class=\"{ 'operator-button--active': localWidget.filterOperator === 'AND' }\"\r\n            @click=\"setFilterOperator('AND')\"\r\n          >\r\n            {{ t('all') }}\r\n          </button>\r\n          <button\r\n            class=\"operator-button\"\r\n            :class=\"{ 'operator-button--active': localWidget.filterOperator === 'OR' }\"\r\n            @click=\"setFilterOperator('OR')\"\r\n          >\r\n            {{ t('any') }}\r\n          </button>\r\n          <span>{{ t('filters') }}</span>\r\n        </div>\r\n      </div>\r\n\r\n      <button class=\"add-filter-button\" @click=\"addFilter\">\r\n        <Plus :size=\"16\" />\r\n        {{ t('Add filter') }}\r\n      </button>\r\n    </div>\r\n\r\n    <div v-else class=\"editor-section metavox-notice\">\r\n      <Information :size=\"20\" />\r\n      <span>{{ t('Install MetaVox for advanced filtering options') }}</span>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script>\r\nimport { translate as t } from '@nextcloud/l10n';\r\nimport { generateUrl } from '@nextcloud/router';\r\nimport axios from '@nextcloud/axios';\r\nimport ViewList from 'vue-material-design-icons/ViewList.vue';\r\nimport ViewGrid from 'vue-material-design-icons/ViewGrid.vue';\r\nimport ViewCarousel from 'vue-material-design-icons/ViewCarousel.vue';\r\nimport SortAscending from 'vue-material-design-icons/SortAscending.vue';\r\nimport SortDescending from 'vue-material-design-icons/SortDescending.vue';\r\nimport Plus from 'vue-material-design-icons/Plus.vue';\r\nimport Close from 'vue-material-design-icons/Close.vue';\r\nimport Information from 'vue-material-design-icons/Information.vue';\r\nimport AlertCircle from 'vue-material-design-icons/AlertCircle.vue';\r\nimport PageTreeSelect from './PageTreeSelect.vue';\r\n\r\nexport default {\r\n  name: 'NewsWidgetEditor',\r\n  components: {\r\n    ViewList,\r\n    ViewGrid,\r\n    ViewCarousel,\r\n    SortAscending,\r\n    SortDescending,\r\n    Plus,\r\n    Close,\r\n    Information,\r\n    AlertCircle,\r\n    PageTreeSelect,\r\n  },\r\n  props: {\r\n    widget: {\r\n      type: Object,\r\n      required: true,\r\n    },\r\n  },\r\n  emits: ['update'],\r\n  data() {\r\n    return {\r\n      localWidget: this.createDefaultWidget(),\r\n      metavoxAvailable: false,\r\n      metavoxFields: [],\r\n      filters: [],\r\n      publicationFieldsConfigured: false,\r\n      // Operators by field type\r\n      operatorsByFieldType: {\r\n        text: [\r\n          { value: 'equals', label: 'equals' },\r\n          { value: 'contains', label: 'contains' },\r\n          { value: 'not_contains', label: 'does not contain' },\r\n          { value: 'not_empty', label: 'is not empty' },\r\n          { value: 'empty', label: 'is empty' },\r\n        ],\r\n        textarea: [\r\n          { value: 'equals', label: 'equals' },\r\n          { value: 'contains', label: 'contains' },\r\n          { value: 'not_contains', label: 'does not contain' },\r\n          { value: 'not_empty', label: 'is not empty' },\r\n          { value: 'empty', label: 'is empty' },\r\n        ],\r\n        date: [\r\n          { value: 'equals', label: 'equals' },\r\n          { value: 'before', label: 'is before' },\r\n          { value: 'after', label: 'is after' },\r\n          { value: 'not_empty', label: 'is not empty' },\r\n          { value: 'empty', label: 'is empty' },\r\n        ],\r\n        number: [\r\n          { value: 'equals', label: 'equals' },\r\n          { value: 'greater_than', label: 'is greater than' },\r\n          { value: 'less_than', label: 'is less than' },\r\n          { value: 'greater_or_equal', label: 'is greater or equal' },\r\n          { value: 'less_or_equal', label: 'is less or equal' },\r\n          { value: 'not_empty', label: 'is not empty' },\r\n          { value: 'empty', label: 'is empty' },\r\n        ],\r\n        select: [\r\n          { value: 'equals', label: 'equals' },\r\n          { value: 'in', label: 'is one of' },\r\n          { value: 'not_empty', label: 'is not empty' },\r\n          { value: 'empty', label: 'is empty' },\r\n        ],\r\n        multiselect: [\r\n          { value: 'contains', label: 'contains' },\r\n          { value: 'contains_all', label: 'contains all' },\r\n          { value: 'not_empty', label: 'is not empty' },\r\n          { value: 'empty', label: 'is empty' },\r\n        ],\r\n        checkbox: [\r\n          { value: 'is_true', label: 'is true' },\r\n          { value: 'is_false', label: 'is false' },\r\n          { value: 'not_empty', label: 'is not empty' },\r\n        ],\r\n      },\r\n    };\r\n  },\r\n  computed: {\r\n    layoutOptions() {\r\n      return [\r\n        { value: 'list', label: this.t('List'), icon: 'ViewList' },\r\n        { value: 'grid', label: this.t('Grid'), icon: 'ViewGrid' },\r\n        { value: 'carousel', label: this.t('Carousel'), icon: 'ViewCarousel' },\r\n      ];\r\n    },\r\n  },\r\n  watch: {\r\n    widget: {\r\n      immediate: true,\r\n      deep: true,\r\n      handler(newWidget) {\r\n        this.localWidget = {\r\n          ...this.createDefaultWidget(),\r\n          ...newWidget,\r\n        };\r\n        this.filters = [...(newWidget.filters || [])];\r\n      },\r\n    },\r\n  },\r\n  mounted() {\r\n    this.checkMetaVox();\r\n  },\r\n  methods: {\r\n    t(key, vars = {}) {\r\n      return t('intravox', key, vars);\r\n    },\r\n    createDefaultWidget() {\r\n      return {\r\n        type: 'news',\r\n        title: '',\r\n        backgroundColor: null,\r\n        sourcePageId: null,\r\n        sourcePath: '',\r\n        layout: 'list',\r\n        columns: 3,\r\n        limit: 5,\r\n        sortBy: 'modified',\r\n        sortOrder: 'desc',\r\n        showImage: true,\r\n        showDate: true,\r\n        showExcerpt: true,\r\n        excerptLength: 100,\r\n        autoplayInterval: 5,\r\n        filters: [],\r\n        filterOperator: 'AND',\r\n        filterPublished: false,\r\n      };\r\n    },\r\n    handleSourceSelect(page) {\r\n      if (page) {\r\n        this.localWidget.sourcePageId = page.uniqueId;\r\n      } else {\r\n        this.localWidget.sourcePageId = null;\r\n      }\r\n      this.emitUpdate();\r\n    },\r\n    async checkMetaVox() {\r\n      try {\r\n        const response = await axios.get(generateUrl('/apps/intravox/api/metavox/status'));\r\n        this.metavoxAvailable = response.data.installed && response.data.enabled;\r\n\r\n        if (this.metavoxAvailable) {\r\n          await this.loadMetaVoxFields();\r\n        }\r\n\r\n        // Always check publication config (it shows a warning if not configured)\r\n        await this.checkPublicationConfig();\r\n      } catch (error) {\r\n        this.metavoxAvailable = false;\r\n      }\r\n    },\r\n    async checkPublicationConfig() {\r\n      try {\r\n        const response = await axios.get(generateUrl('/apps/intravox/api/settings/publication'));\r\n        const settings = response.data;\r\n        this.publicationFieldsConfigured = !!(settings.publishDateField || settings.expirationDateField);\r\n      } catch (error) {\r\n        this.publicationFieldsConfigured = false;\r\n      }\r\n    },\r\n    async loadMetaVoxFields() {\r\n      try {\r\n        // Get fields from IntraVox API which fetches MetaVox fields for the IntraVox groupfolder\r\n        const response = await axios.get(generateUrl('/apps/intravox/api/metavox/fields'));\r\n        this.metavoxFields = response.data.fields || [];\r\n      } catch (error) {\r\n        // MetaVox API might not be available\r\n        this.metavoxFields = [];\r\n      }\r\n    },\r\n    setLayout(layout) {\r\n      this.localWidget.layout = layout;\r\n      this.emitUpdate();\r\n    },\r\n    setColumns(cols) {\r\n      this.localWidget.columns = cols;\r\n      this.emitUpdate();\r\n    },\r\n    toggleSortOrder() {\r\n      this.localWidget.sortOrder = this.localWidget.sortOrder === 'desc' ? 'asc' : 'desc';\r\n      this.emitUpdate();\r\n    },\r\n    addFilter() {\r\n      this.filters.push({\r\n        fieldName: '',\r\n        operator: 'equals',\r\n        value: '',\r\n        values: [], // For 'in' and multiselect operators\r\n      });\r\n      // Don't call syncFilters() here - it would remove the empty filter immediately\r\n      // The filter will be synced when user selects a field\r\n    },\r\n    getFieldType(fieldName) {\r\n      const field = this.metavoxFields.find(f => f.field_name === fieldName);\r\n      return field?.field_type || 'text';\r\n    },\r\n    getOperatorsForField(fieldName) {\r\n      const fieldType = this.getFieldType(fieldName);\r\n      return this.operatorsByFieldType[fieldType] || this.operatorsByFieldType.text;\r\n    },\r\n    getFieldOptions(fieldName) {\r\n      const field = this.metavoxFields.find(f => f.field_name === fieldName);\r\n      if (!field?.options) {\r\n        return [];\r\n      }\r\n\r\n      let options = field.options;\r\n\r\n      // Handle string options (newline-separated or JSON array)\r\n      if (typeof options === 'string') {\r\n        // Try to parse as JSON array first\r\n        if (options.startsWith('[')) {\r\n          try {\r\n            options = JSON.parse(options);\r\n          } catch (e) {\r\n            // Not valid JSON, treat as newline-separated\r\n            options = options.split('\\n').filter(o => o.trim());\r\n          }\r\n        } else {\r\n          // Newline-separated options\r\n          options = options.split('\\n').filter(o => o.trim());\r\n        }\r\n      }\r\n\r\n      // Ensure we have an array\r\n      if (!Array.isArray(options)) {\r\n        return [];\r\n      }\r\n\r\n      return options.filter(o => o && (typeof o === 'string' ? o.trim() : true));\r\n    },\r\n    handleFieldChange(filter) {\r\n      const fieldType = this.getFieldType(filter.fieldName);\r\n      const validOperators = this.operatorsByFieldType[fieldType] || this.operatorsByFieldType.text;\r\n\r\n      // Reset to first valid operator if current is not valid\r\n      if (!validOperators.find(op => op.value === filter.operator)) {\r\n        filter.operator = validOperators[0].value;\r\n      }\r\n\r\n      // Clear values when switching fields\r\n      filter.value = '';\r\n      filter.values = [];\r\n\r\n      this.syncFilters();\r\n    },\r\n    handleOperatorChange(filter) {\r\n      // Clear values array when not using 'in' or multiselect operators\r\n      if (!['in', 'contains', 'contains_all'].includes(filter.operator)) {\r\n        filter.values = [];\r\n      }\r\n      this.emitUpdate();\r\n    },\r\n    requiresNoValue(operator) {\r\n      return ['not_empty', 'empty', 'is_true', 'is_false'].includes(operator);\r\n    },\r\n    removeFilter(index) {\r\n      this.filters.splice(index, 1);\r\n      this.syncFilters();\r\n    },\r\n    setFilterOperator(operator) {\r\n      this.localWidget.filterOperator = operator;\r\n      this.emitUpdate();\r\n    },\r\n    syncFilters() {\r\n      this.localWidget.filters = this.filters.filter(f => f.fieldName);\r\n      this.emitUpdate();\r\n    },\r\n    emitUpdate() {\r\n    